#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char S[N + 1];
        scanf("%s", S);
        int destroyed[N];
        memset(destroyed, 0, sizeof(destroyed));
        for (int i = 0; i < N; i++) {
            if (S[i] == '1') {
                if (i - 1 >= 0) destroyed[i - 1] = 1;
                destroyed[i] = 1;
                if (i + 1 < N) destroyed[i + 1] = 1;
            }
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (!destroyed[i]) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

