import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            String S = sc.next();
            boolean[] destroyed = new boolean[N];
            for (int i = 0; i < N; i++) {
                if (S.charAt(i) == '1') {
                    if (i - 1 >= 0) destroyed[i - 1] = true;
                    destroyed[i] = true;
                    if (i + 1 < N) destroyed[i + 1] = true;
                }
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                if (!destroyed[i]) count++;
            }
            System.out.println(count);
        }
    }
}

